using System.Text.Json.Serialization;

using API.Protocol.Status.Components;
using API.Text;

namespace API.Protocol.Status;

public class StatusResponseFormat
{
    [JsonPropertyName("version")]
    public StatusVersionComponent version { get; set; } = new StatusVersionComponent();

    [JsonPropertyName("players")]
    public PlayerListComponent players { get; set; } = new  PlayerListComponent();

    [JsonPropertyName("description")]
    [JsonConverter(typeof(TextComponentConverter))]
    public TextComponentBuilder Description { get; set; } = new();

    [JsonPropertyName("favicon")]
    public string Favicon { get; set; } = "data:image/png;base64,";

    [JsonPropertyName("enforcesSecureChat")]
    public bool EnforceSecureChat { get; set; } = false;
    
}